import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('http://localhost:8089/users/auth/login', {
        email,
        password
      });
      if (response.data && response.data.access_token) {
        localStorage.setItem('token', response.data.access_token);
        navigate('/');
      }
    } catch (err) {
      setError('Identifiants incorrects ou erreur serveur.');
    } finally {
      setLoading(false);
    }
  };

  const handleKeycloakLogin = () => {
    // Bouton de remplacement pour la future intégration Keycloak (SSO)
    alert("Authentification locale via la base de données sélectionnée.");
  };

  return (
    <div className="login-container">
      <div className="login-blob blob-1"></div>
      <div className="login-blob blob-2"></div>

      <div className="login-card">
        <div className="login-header">
          <div className="login-logo-icon">🎓</div>
          <h2>Campus MS</h2>
          <p>Connectez-vous à votre espace universitaire</p>
        </div>

        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label className="form-label">Email étudiant / personnel</label>
            <input 
              type="email" 
              className="form-input" 
              placeholder="votre.nom@campus.edu"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div className="form-group">
            <label className="form-label">Mot de passe</label>
            <input 
              type="password" 
              className="form-input" 
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <div className="login-options">
            <label className="remember-me">
              <input type="checkbox" /> Se souvenir de moi
            </label>
            <a href="#" className="forgot-password">Mot de passe oublié ?</a>
          </div>

          <button type="submit" className="btn btn-primary login-btn" disabled={loading}>
            {loading ? <div className="spinner-small"></div> : 'Se connecter'}
          </button>
        </form>

        <div className="login-divider">
          <span>ou</span>
        </div>

        <button type="button" onClick={handleKeycloakLogin} className="btn login-keycloak-btn">
          <span className="keycloak-icon">🔐</span> Connexion avec Keycloak (SSO)
        </button>
      </div>
    </div>
  );
}
